#!/usr/bin/env Rscript

#this script calculates the drive time to the nearest acute hospital for a specified state using 2023 OSM roads and hospitals
# make sure that cl_00_UNC_hosps.R is run and that state osm.pbf files are in the correct directory generated by cl_01_OSM_state_pbfs.sh

# Load libraries silently for CLI clean output
suppressPackageStartupMessages({
  library(optparse)
  library(tigris)
  library(dplyr)
  library(osrm)
  library(sf)
  library(stringr)
  library(tidyr)
  library(here)
})

# 1. PARSE COMMAND LINE ARGUMENTS
option_list <- list(
  make_option(c("-s", "--state"), type = "character", default = NULL, 
              help = "State abbreviation or FIPS code (e.g., VA or 51)", metavar = "character")
)

opt_parser <- OptionParser(option_list = option_list)
opt <- parse_args(opt_parser)

if (is.null(opt$state)) {
  print_help(opt_parser)
  stop("Error: You must provide a --state argument.", call. = FALSE)
}

# Resolve State FIPS, Abbreviation, and Full Name using tigris maps
target_state <- opt$state
state_lookup <- tigris::fips_codes %>% 
  filter(state == toupper(target_state) | state_code == target_state) %>% 
  distinct(state, state_code, state_name)

if (nrow(state_lookup) == 0) {
  stop(paste("Error: Invalid state or FIPS code provided:", target_state), call. = FALSE)
}

state_fips <- state_lookup$state_code[1]
state_abb  <- tolower(state_lookup$state[1])

# Format full state name e.g., "District of Columbia" -> "district-of-columbia"
state_full_name <- state_lookup$state_name[1] %>% 
  tolower() %>% 
  stringr::str_replace_all(" ", "-")

message(paste0("Processing State: ", state_lookup$state_name[1], " (", toupper(state_abb), ")"))

# 2. LOAD SOURCE DATASETS

us_counties = readRDS("data/outcome/census/us_counties_2023.rds") %>% st_as_sf()
hosp_sf = readRDS("data/outcome/UNC_shep/clean_UNC_hosps_acute_2023.rds") %>% st_as_sf()
centers_sf = readRDS("data/outcome/census/clean_pop_centroids_2020.rds") %>% st_as_sf()

# 3. SPATIAL FILTERING & PREPARATION

# Filter for target state
state_counties <- us_counties %>% filter(STATEFP == state_fips)

state_hosps <- hosp_sf %>% filter(STATEFP == state_fips)

state_centers <- centers_sf %>% filter(STATEFP == state_fips)

if (nrow(state_hosps) == 0 || nrow(state_centers) == 0) {
  stop("No hospitals or census tracts found for this state. Check underlying source data alignment.")
}

# 4. INITIALIZE LOCAL OSRM SERVER ROUTE

# Force R to the project root directory
setwd(here::here())

# Build the absolute path to where the PBFs live
data_dir <- here::here("data/outcome/OSM_states_2023")

# Pass both the state name AND the data directory to the shell script
startup_cmd <- paste0("./in_00_start_osrm.sh ", state_full_name, " ", shQuote(data_dir))

message(paste("Spinning up local OSRM server for:", state_full_name))
exit_code <- system(startup_cmd)

if (exit_code != 0) {
  stop("Failed to start OSRM server. Aborting R script execution.", call. = FALSE)
}

Sys.sleep(3)
options(osrm.server = "http://localhost:5000/")


# 5. EFFICIENT ROUTING MATRIX (10 Nearest Neighbors)
all_tract_results <- list()
tract_ids <- state_centers$tractce

message("Calculating 10 nearest hospitals for each census tract via straight-line distance...")

# Calculate a fast Euclidean/Great-Circle distance matrix between all centers and hospitals
# to narrow down the pool before spinning wheels on the OSRM routing engine.
geo_dist_matrix <- st_distance(state_centers, state_hosps)

for (i in seq_len(nrow(state_centers))) {
  current_tract <- state_centers[i, ]
  t_id <- current_tract$TRACTCE
  c_id <- current_tract$COUNTYFP
  
  # Find indices of the 10 closest hospitals geometrically
  closest_hosp_idx <- order(geo_dist_matrix[i, ])[1:min(10, ncol(geo_dist_matrix))]
  current_hosps <- state_hosps[closest_hosp_idx, ]
  
  # Assign row IDs for matrix extraction mapping
  rownames(current_tract) <- t_id
  rownames(current_hosps) <- current_hosps$id
  
  # Query OSRM table on ONLY the 10 candidates
  osrm_matrix <- tryCatch(
    osrmTable(
      src = current_tract,
      dst = current_hosps,
      measure = c("duration", "distance")
    ),
    error = function(e) {
      NULL
    }
  )
  
  if (is.null(osrm_matrix)) next
  
  # Flatten and format table outputs
  dist_df <- as.data.frame(osrm_matrix$distances) %>%
    mutate(tract_id = t_id) %>%
    pivot_longer(cols = -tract_id, names_to = "hospital_id", values_to = "distance_meters")
  
  dur_df <- as.data.frame(osrm_matrix$durations) %>%
    mutate(tract_id = t_id) %>%
    pivot_longer(cols = -tract_id, names_to = "hospital_id", values_to = "duration_minutes")
  
  # Merge routing specs
  complete_tract_df <- left_join(dist_df, dur_df, by = c("tract_id", "hospital_id")) %>% 
    mutate(county_id = c_id)
  
  all_tract_results[[t_id]] <- complete_tract_df
}


# 6. COMBINE AND SUMMARY METRICS
final_access_df <- bind_rows(all_tract_results)

average_county_access <- final_access_df %>%
  group_by(county_id, tract_id) %>%
  filter(duration_minutes == min(duration_minutes, na.rm = TRUE)) %>%
  ungroup() %>%
  
  group_by(county_id) %>%
  summarize(
    avg_drive_time_minutes = mean(duration_minutes, na.rm = TRUE),
    max_drive_time_minutes = max(duration_minutes, na.rm = TRUE),
    min_drive_time_minutes = min(duration_minutes, na.rm = TRUE),
    total_tracts_evaluated = n_distinct(tract_id),
    .groups = "drop"
  )


# 7. GENERATE EXPORTS (State-Prefixed)

mapdat <- state_counties %>% 
  left_join(average_county_access, by = c("COUNTYFP" = "county_id"))

saveRDS(mapdat, paste0("data/outcome/OSM/drive_times/", state_abb, "acute_hosp_drive_times.rds"))

message(paste("Processing complete for", toupper(state_abb), ". Files saved!"))

# 8. AUTOMATED OSRM CONTAINER TEARDOWN
message("Decommissioning local OSRM server...")

# Formulate the container name dynamically based on the CLI input
container_name <- paste0("osrm_", state_full_name)

# Stop and remove the Docker container
system(paste("docker stop", container_name), ignore.stdout = TRUE, ignore.stderr = TRUE)
system(paste("docker rm", container_name), ignore.stdout = TRUE, ignore.stderr = TRUE)

# Optional: Clean up the heavy processed .osrm files to free disk space immediately
# system(paste0("rm -f ", state_abb, "-latest.osrm*"))

message("Server cleanup complete")